/* eslint-disable no-bitwise */
import {
    MAX_U128_BIG_INT,
    MAX_U16_NUMBER,
    MAX_U256_BIG_INT,
    MAX_U32_NUMBER,
    MAX_U64_BIG_INT,
    MAX_U8_NUMBER,
} from './consts'
import { AnyNumber, Bytes, Uint16, Uint32, Uint8 } from './types'

/**
 * Class representing a serializer for various data types.
 */
export class Serializer {
    private buffer: ArrayBuffer

    private offset: number
    public readonly littleEndian: boolean

    /**
     * Creates an instance of Serializer.
     *
     * @param {boolean} [littleEndian=true] - Whether to use little-endian byte order.
     */
    constructor(littleEndian = true) {
        this.littleEndian = littleEndian
        this.buffer = new ArrayBuffer(64)
        this.offset = 0
    }

    /**
     * Ensures that the buffer has enough space to handle the specified number of bytes.
     * If the buffer is not large enough, it will be resized to accommodate the additional bytes.
     *
     * @param {number} bytes - The number of bytes to ensure space for.
     */
    private ensureBufferWillHandleSize(bytes: number): void {
        while (this.buffer.byteLength < this.offset + bytes) {
            const newBuffer = new ArrayBuffer(this.buffer.byteLength * 2)
            new Uint8Array(newBuffer).set(new Uint8Array(this.buffer))
            this.buffer = newBuffer
        }
    }

    /**
     * Serializes the given byte values into the buffer.
     *
     * @param {Bytes} values - The byte values to serialize.
     */
    protected serialize(values: Bytes): void {
        this.ensureBufferWillHandleSize(values.length)
        new Uint8Array(this.buffer, this.offset).set(values)
        this.offset += values.length
    }

    /**
     * Serializes a value using the specified DataView function.
     *
     * @param {(byteOffset: number, value: number, littleEndian?: boolean) => void} fn - The DataView function to use for serialization.
     * @param {number} bytesLength - The length of the bytes to serialize.
     * @param {number} value - The value to serialize.
     */
    private serializeWithFunction(
        fn: (byteOffset: number, value: number, littleEndian?: boolean) => void,
        bytesLength: number,
        value: number
    ): void {
        this.ensureBufferWillHandleSize(bytesLength)
        const dv = new DataView(this.buffer, this.offset)
        fn.apply(dv, [0, value, this.littleEndian])
        this.offset += bytesLength
    }

    /**
     * Serializes a string. UTF8 string is supported. Serializes the string's bytes length "l" first,
     * and then serializes "l" bytes of the string content.
     *
     * layout for "string": string_length | string_content. string_length is the bytes length of
     * the string that is uleb128/ubeb128 encoded. string_length is a u32 integer.
     *
     * @example
     * ```ts
     * const serializer = new Serializer();
     * serializer.serializeStr("çå∞≠¢õß∂ƒ∫");
     * assert(serializer.getBytes() === new Uint8Array([24, 0xc3, 0xa7, 0xc3, 0xa5, 0xe2, 0x88, 0x9e,
     * 0xe2, 0x89, 0xa0, 0xc2, 0xa2, 0xc3, 0xb5, 0xc3, 0x9f, 0xe2, 0x88, 0x82, 0xc6, 0x92, 0xe2, 0x88, 0xab]));
     * ```
     */
    serializeStr(value: string): this {
        const textEncoder = new TextEncoder()
        this.serializeBytes(textEncoder.encode(value))
        return this
    }

    /**
     * Serializes an array of bytes.
     *
     * layout for "bytes": bytes_length | bytes. bytes_length is the length of the bytes array that is
     * uleb128/ubeb128 encoded. bytes_length is a u32 integer.
     */
    serializeBytes(value: Bytes): this {
        if (this.littleEndian) {
            this.serializeU32AsUleb128(value.length)
        } else {
            this.serializeU32AsUbeb128(value.length)
        }
        this.serialize(value)
        return this
    }

    /**
     * Serializes an array of bytes with known length. Therefore length doesn't need to be
     * serialized to help deserialization.  When deserializing, the number of
     * bytes to deserialize needs to be passed in.
     */
    serializeFixedBytes(value: Bytes): this {
        this.serialize(value)
        return this
    }

    /**
     * Serializes a boolean value.
     *
     * layout for "boolean": One byte. "0x01" for True and "0x00" for False.
     */
    serializeBool(value: boolean): this {
        if (typeof value !== 'boolean') {
            throw new Error('Value needs to be a boolean')
        }
        const byteValue = value ? 1 : 0
        this.serialize(new Uint8Array([byteValue]))
        return this
    }

    /**
     * Serializes a uint8 number.
     *
     * layout for "uint8": One byte. Binary format in little-endian representation.
     */
    @checkNumberRange(0, MAX_U8_NUMBER)
    serializeU8(value: Uint8): this {
        this.serialize(new Uint8Array([value]))
        return this
    }

    /**
     * Serializes a uint16 number.
     *
     * layout for "uint16": Two bytes. Binary format in little-endian representation.
     * @example
     * ```ts
     * const serializer = new Serializer(true);
     * serializer.serializeU16(4660);
     * assert(serializer.getBytes() === new Uint8Array([0x34, 0x12]));
     * const serializer = new Serializer(false);
     * serializer.serializeU16(4660);
     * assert(serializer.getBytes() === new Uint8Array([0x12, 0x34]));
     * ```
     */
    @checkNumberRange(0, MAX_U16_NUMBER)
    serializeU16(value: Uint16): this {
        // eslint-disable-next-line @typescript-eslint/unbound-method
        this.serializeWithFunction(DataView.prototype.setUint16, 2, value)
        return this
    }

    /**
     * Serializes a uint32 number.
     *
     * layout for "uint32": Four bytes. Binary format in little-endian representation.
     * @example
     * ```ts
     * const serializer = new Serializer(true);
     * serializer.serializeU32(305419896);
     * assert(serializer.getBytes() === new Uint8Array([0x78, 0x56, 0x34, 0x12]));
     * const serializer = new Serializer(false);
     * serializer.serializeU32(305419896);
     * assert(serializer.getBytes() === new Uint8Array([0x12, 0x34, 0x56, 0x78]));
     * ```
     */
    @checkNumberRange(0, MAX_U32_NUMBER)
    serializeU32(value: Uint32): this {
        // eslint-disable-next-line @typescript-eslint/unbound-method
        this.serializeWithFunction(DataView.prototype.setUint32, 4, value)
        return this
    }

    /**
     * Serializes a uint64 number.
     *
     * layout for "uint64": Eight bytes. Binary format in little-endian representation.
     * @example
     * ```ts
     * const serializer = new Serializer(true);
     * serializer.serializeU64(1311768467750121216);
     * assert(serializer.getBytes() === new Uint8Array([0x00, 0xEF, 0xCD, 0xAB, 0x78, 0x56, 0x34, 0x12]));
     * const serializer = new Serializer(false);
     * serializer.serializeU64(1311768467750121216);
     * assert(serializer.getBytes() === new Uint8Array([0x12, 0x34, 0x56, 0x78, 0xAB, 0xCD, 0xEF, 0x00]));
     * ```
     */
    @checkNumberRange(BigInt(0), MAX_U64_BIG_INT)
    serializeU64(value: AnyNumber): this {
        const low = BigInt(value.toString()) & BigInt(MAX_U32_NUMBER)
        const high = BigInt(value.toString()) >> BigInt(32)

        const array = this.littleEndian ? [low, high] : [high, low]
        array.forEach((x) => {
            this.serializeU32(Number(x))
        })
        return this
    }

    /**
     * Serializes a uint128 number.
     *
     * layout for "uint128": Sixteen bytes. Binary format in little-endian representation.
     */
    @checkNumberRange(BigInt(0), MAX_U128_BIG_INT)
    serializeU128(value: AnyNumber): this {
        const low = BigInt(value.toString()) & MAX_U64_BIG_INT
        const high = BigInt(value.toString()) >> BigInt(64)

        const array = this.littleEndian ? [low, high] : [high, low]
        array.forEach((x) => {
            this.serializeU64(x)
        })
        return this
    }

    /**
     * Serializes a uint256 number.
     *
     * layout for "uint256": Sixteen bytes. Binary format in little-endian representation.
     */
    @checkNumberRange(BigInt(0), MAX_U256_BIG_INT)
    serializeU256(value: AnyNumber): this {
        const low = BigInt(value.toString()) & MAX_U128_BIG_INT
        const high = BigInt(value.toString()) >> BigInt(128)

        const array = this.littleEndian ? [low, high] : [high, low]
        array.forEach((x) => {
            this.serializeU128(x)
        })
        return this
    }

    /**
     * Serializes a uint32 number with uleb128.
     *
     * use uleb128 encoding in two cases: (1) lengths of variable-length sequences and (2) tags of enum values
     */
    @checkNumberRange(0, MAX_U32_NUMBER)
    serializeU32AsUleb128(val: Uint32): this {
        let value = val
        const valueArray = []
        while (value >>> 7 !== 0) {
            valueArray.push((value & 0x7f) | 0x80)
            value >>>= 7
        }
        valueArray.push(value)
        this.serialize(new Uint8Array(valueArray))
        return this
    }

    /**
     * Serializes a uint32 number with unsigned Variable-Length Big-Endian Encoding.
     *
     * use ubeb128 encoding in two cases: (1) lengths of variable-length sequences and (2) tags of enum values
     */
    @checkNumberRange(0, MAX_U32_NUMBER)
    serializeU32AsUbeb128(val: Uint32): this {
        let value = val
        const valueArray: Uint8[] = []

        valueArray.unshift(value & 0x7f)
        while (value >>> 7 !== 0) {
            value >>>= 7
            const byte = (value & 0x7f) | 0x80
            valueArray.unshift(byte)
        }

        this.serialize(new Uint8Array(valueArray))
        return this
    }

    /**
     * Returns the buffered bytes
     *
     * @returns {Bytes} The buffered bytes.
     */
    getBytes(): Bytes {
        return new Uint8Array(this.buffer).slice(0, this.offset)
    }
}

/**
 * Creates a decorator to make sure the arg value of the decorated function is within a range.
 * @param minValue The arg value of decorated function must >= minValue
 * @param maxValue The arg value of decorated function must <= maxValue
 * @param message Error message
 */
function checkNumberRange<T extends AnyNumber>(minValue: T, maxValue: T, message?: string) {
    return (target: unknown, propertyKey: string, descriptor: PropertyDescriptor): PropertyDescriptor => {
        /* eslint-disable @typescript-eslint/no-unsafe-assignment */
        const childFunction = descriptor.value as (value: AnyNumber) => any
        // eslint-disable-next-line no-param-reassign
        descriptor.value = function deco(value: AnyNumber): void {
            const valueBigInt = BigInt(value.toString())
            if (valueBigInt > BigInt(maxValue.toString()) || valueBigInt < BigInt(minValue.toString())) {
                throw new Error(message ?? 'Value is out of range')
            }
            // eslint-disable-next-line @typescript-eslint/no-unsafe-return
            return childFunction.apply(this, [value])
        }
        return descriptor
        /* eslint-enable @typescript-eslint/no-unsafe-assignment */
    }
}
