import { Uint128, Uint16, Uint256, Uint32, Uint64, Uint8 } from './types'

/**
 * Upper bound value for uint8.
 * @type {Uint8}
 */
export const MAX_U8_NUMBER: Uint8 = 255

/**
 * Upper bound value for uint16.
 * @type {Uint16}
 */
export const MAX_U16_NUMBER: Uint16 = 65535

/**
 * Upper bound value for uint32.
 * @type {Uint32}
 */
export const MAX_U32_NUMBER: Uint32 = 4294967295

/**
 * Upper bound value for uint64.
 * @type {Uint64}
 */
export const MAX_U64_BIG_INT: Uint64 = 18446744073709551615n

/**
 * Upper bound value for uint128.
 * @type {Uint128}
 */
export const MAX_U128_BIG_INT: Uint128 = 340282366920938463463374607431768211455n

/**
 * Upper bound value for uint256.
 * @type {Uint256}
 */
export const MAX_U256_BIG_INT: Uint256 = 115792089237316195423570985008687907853269984665640564039457584007913129639935n
